/**
 * Stage 05 — Registrations
 *
 * Generates registration rows deterministically using a per-event LCG seeded
 * from djb2Hash(event_slug).  Order per event: heroes → fixtures → guests
 * (confirmed, cancelled, refunded, pending, waitlisted).
 *
 * TRIGGER NOTE:
 *   trg_registration_count (AFTER INSERT OR UPDATE) auto-increments
 *   events.registration_count and ticket_types.quantity_sold when status='confirmed'.
 *   DO NOT set those counters manually.
 *
 *   qr_code and certificate_token are auto-generated by DB defaults — NEVER
 *   included in insert payloads (unique constraint on both).
 *
 * Batch limit: ≤200 rows per supabase .insert() call.
 */

import type { SupabaseClient } from '@supabase/supabase-js'
import type { EventsFileData, EventDef, TicketTypeDef, FormFieldDef } from '../lib/event-types'
import { log } from '../lib/logger'
import type { StageSummary } from '../lib/logger'

// ─── Public types (re-exported for run.ts) ────────────────────────────────────

export interface DiscountCodeDef {
  id: string
  event_slug: string
  code: string
  discount_type: 'percent' | 'fixed'
  discount_value: number
  max_uses?: number
  uses_count?: number
  valid_until?: string
  is_active?: boolean
}

export interface FieldResponseRates {
  dietary_restrictions_rate?: number
  tshirt_size_rate?: number
  company_name_rate?: number
  experience_level_rate?: number
}

export interface EventRegDef {
  slug: string
  confirmed?: number
  pending?: number
  cancelled?: number
  waitlisted?: number
  refunded?: number
  delivery_method?: 'in_person' | 'virtual'
  delivery_split?: Record<string, number>
  ticket_split: Record<string, number>
  hero_emails: string[]
  fixture_indices: number[]
  sms_opt_in_rate?: number
  discounted_ticket?: string
  discounted_count?: number
  discount_code_id?: string
  discount_amount_cents?: number
  ce_field_responses?: boolean
  member_id_rate?: number
  field_responses?: FieldResponseRates
}

export interface RegistrationsFileData {
  discount_codes: DiscountCodeDef[]
  events: EventRegDef[]
}

// ─── LCG seeded RNG ───────────────────────────────────────────────────────────

function djb2Hash(s: string): number {
  let h = 5381
  for (let i = 0; i < s.length; i++) h = (((h << 5) + h) + s.charCodeAt(i)) & 0xffffffff
  return h >>> 0
}

class Lcg {
  private s: number
  constructor(seed: number) { this.s = seed >>> 0 }
  next(): number {
    this.s = (Math.imul(1664525, this.s) + 1013904223) >>> 0
    return this.s
  }
  float(): number { return this.next() / 0x100000000 }
  int(max: number): number { return max <= 0 ? 0 : this.next() % max }
}

